  1→import { afterAll, describe, expect, it, test } from "bun:test";
  2→import { createClickHouseExecutor } from "@chkit/clickhouse";
  3→import { ingestRudelClaudeSessions } from "../generated/chkit-ingest.js";
  4→import type { RudelClaudeSessionsRow } from "../generated/chkit-types.js";
  5→
  6→const testId = `test_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
  7→
  8→const baseExecutor = createClickHouseExecutor({
  9→	url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
 10→	username:
 11→		process.env.CLICKHOUSE_USERNAME || process.env.CLICKHOUSE_USER || "default",
 12→	password: process.env.CLICKHOUSE_PASSWORD || "",
 13→	database: "default",
 14→});
 15→
 16→// ClickHouse Cloud's @clickhouse/client insert() silently drops data.
 17→// Wrap the executor to use execute() with FORMAT JSONEachRow instead.
 18→// async_insert=0 forces synchronous insert so data is immediately queryable.
 19→const executor: typeof baseExecutor = {
 20→	...baseExecutor,
 21→	async insert(params) {
 22→		const rows = params.values
 23→			.map((r: Record<string, unknown>) => JSON.stringify(r))
 24→			.join("\n");
 25→		const sql = `INSERT INTO ${params.table} SETTINGS async_insert=0 FORMAT JSONEachRow ${rows}`;
 26→		for (let attempt = 0; attempt < 5; attempt++) {
 27→			try {
 28→				await baseExecutor.execute(sql);
 29→				return;
 30→			} catch (error) {
 31→				const isRaceCondition =
 32→					error instanceof Error &&
 33→					error.message.includes("INSERT race condition");
 34→				if (!isRaceCondition || attempt === 4) throw error;
 35→				await new Promise((r) => setTimeout(r, 1000 * 2 ** attempt));
 36→			}
 37→		}
 38→	},
 39→};
 40→
 41→async function waitForQuery<T>(
 42→	query: string,
 43→	timeoutMs = 30000,
 44→	intervalMs = 2000,
 45→): Promise<T[]> {
 46→	const start = Date.now();
 47→	while (Date.now() - start < timeoutMs) {
 48→		try {
 49→			const results = await executor.query<T>(query);
 50→			if (results.length > 0) return results;
 51→		} catch {
 52→			// Transient ClickHouse errors (e.g. S3 storage) - retry
 53→		}
 54→		await new Promise((r) => setTimeout(r, intervalMs));
 55→	}
 56→	return [];
 57→}
 58→
 59→async function insertWithRetry(
 60→	fn: () => Promise<void>,
 61→	queryFn: () => Promise<unknown[]>,
 62→	maxAttempts = 5,
 63→): Promise<unknown[]> {
 64→	for (let attempt = 0; attempt < maxAttempts; attempt++) {
 65→		try {
 66→			await fn();
 67→		} catch (error) {
 68→			// Retry on transient ClickHouse errors (e.g. INSERT race conditions)
 69→			if (attempt === maxAttempts - 1) throw error;
 70→			await new Promise((r) => setTimeout(r, 2000 * 2 ** attempt));
 71→			continue;
 72→		}
 73→		const results = await queryFn();
 74→		if (results.length > 0) return results;
 75→	}
 76→	return [];
 77→}
 78→
 79→afterAll(() => {
 80→	executor
 81→		.execute(`DELETE FROM rudel.claude_sessions WHERE session_id = '${testId}'`)
 82→		.catch(() => {});
 83→});
 84→
 85→describe("ingestRudelClaudeSessions", () => {
 86→	const now = new Date().toISOString().replace("Z", "");
 87→	const row: RudelClaudeSessionsRow = {
 88→		session_date: now,
 89→		last_interaction_date: now,
 90→		session_id: testId,
 91→		organization_id: "org_test",
 92→		project_path: "/test/project",
 93→		repository: null,
 94→		content: "test session content",
 95→		subagents: {},
 96→		skills: ["code:testing"],
 97→		slash_commands: [],
 98→		subagent_types: [],
 99→		ingested_at: now,
100→		user_id: "user_test",
101→		git_branch: "main",
102→		git_sha: null,
103→		input_tokens: "100",
104→		output_tokens: "200",
105→		cache_read_input_tokens: "0",
106→		cache_creation_input_tokens: "0",
107→		total_tokens: "300",
108→		tag: "integration-test",
109→	};
110→
111→	test("inserts a row and reads it back", async () => {
112→		const results = (await insertWithRetry(
113→			() => ingestRudelClaudeSessions(executor, [row]),
114→			() =>
115→				waitForQuery<{ session_id: string; tag: string }>(
116→					`SELECT session_id, tag FROM rudel.claude_sessions WHERE session_id = '${testId}' LIMIT 1`,
117→				),
118→		)) as Array<{ session_id: string; tag: string }>;
119→
120→		expect(results).toHaveLength(1);
121→		expect(results[0]?.session_id).toBe(testId);
122→		expect(results[0]?.tag).toBe("integration-test");
123→	}, 120000);
124→
125→	it("rejects invalid data with validate option", async () => {
126→		const badRow = {
127→			...row,
128→			input_tokens: 999,
129→		} as unknown as RudelClaudeSessionsRow;
130→		expect(
131→			ingestRudelClaudeSessions(executor, [badRow], { validate: true }),
132→		).rejects.toThrow();
133→	});
134→});
